 11→// ─────────────────────────────────────────────────────────────────────────────
 12→// JSONB extraction helpers
 13→// ─────────────────────────────────────────────────────────────────────────────
 14→
 15→// jsonbObject returns a nested map from data[key], or nil if absent/wrong type.
 16→func jsonbObject(data map[string]any, key string) map[string]any {
 17→	v, ok := data[key]
 18→	if !ok || v == nil {
 19→		return nil
 20→	}
 21→	m, ok := v.(map[string]any)
 22→	if !ok {
 23→		return nil
 24→	}
 25→	return m
 26→}
 27→
 28→// jsonbString extracts a string value from data[key]. Returns nil if absent or
 29→// not a string.
 30→func jsonbString(data map[string]any, key string) *string {
 31→	v, ok := data[key]
 32→	if !ok || v == nil {
 33→		return nil
 34→	}
 35→	switch s := v.(type) {
 36→	case string:
 37→		return &s
 38→	default:
 39→		str := fmt.Sprintf("%v", v)
 40→		return &str
 41→	}
 42→}
 43→
 44→// jsonbInt extracts an integer value from data[key]. Handles float64 (JSON
 45→// default), string, and json.Number representations.
 46→func jsonbInt(data map[string]any, key string) *int {
 47→	v, ok := data[key]
 48→	if !ok || v == nil {
 49→		return nil
 50→	}
 51→	switch n := v.(type) {
 52→	case float64:
 53→		if math.IsNaN(n) || math.IsInf(n, 0) {
 54→			return nil
 55→		}
 56→		i := int(n)
 57→		return &i
 58→	case string:
 59→		i, err := strconv.Atoi(n)
 60→		if err != nil {
 61→			return nil
 62→		}
 63→		return &i
 64→	default:
 65→		return nil
 66→	}
 67→}
 68→
 69→// jsonbFloat extracts a float64 value from data[key]. Handles float64, string,
 70→// and integer representations.
 71→func jsonbFloat(data map[string]any, key string) *float64 {
 72→	v, ok := data[key]
 73→	if !ok || v == nil {
 74→		return nil
 75→	}
 76→	switch n := v.(type) {
 77→	case float64:
 78→		if math.IsNaN(n) || math.IsInf(n, 0) {
 79→			return nil
 80→		}
 81→		return &n
 82→	case string:
 83→		f, err := strconv.ParseFloat(n, 64)
 84→		if err != nil {
 85→			return nil
 86→		}
 87→		return &f
 88→	default:
 89→		return nil
 90→	}
 91→}
 92→
 93→// jsonbBool01 interprets data[key] as a boolean from "0"/"1" or 0/1.
 94→func jsonbBool01(data map[string]any, key string) *bool {
 95→	v, ok := data[key]
 96→	if !ok || v == nil {
 97→		return nil
 98→	}
 99→	switch n := v.(type) {
100→	case string:
101→		b := n == "1"
102→		return &b
103→	case float64:
104→		b := n == 1
105→		return &b
106→	default:
107→		return nil
108→	}
109→}
110→
111→// jsonbStringSlice extracts a []string from data[key] where the value is a
112→// JSON array of strings.
113→func jsonbStringSlice(data map[string]any, key string) []string {
114→	v, ok := data[key]
115→	if !ok || v == nil {
116→		return nil
117→	}
118→	arr, ok := v.([]any)
119→	if !ok {
120→		return nil
121→	}
122→	out := make([]string, 0, len(arr))
123→	for _, elem := range arr {
124→		if s, ok := elem.(string); ok {
125→			out = append(out, s)
126→		}
127→	}
128→	if len(out) == 0 {
129→		return nil
130→	}
131→	return out
132→}
