138→func extractLocation(data map[string]any) *model.InstitutionLocation {
139→	nces := jsonbObject(data, "nces")
140→	metro := jsonbObject(data, "metro_area")
141→
142→	loc := &model.InstitutionLocation{}
143→	if nces != nil {
144→		loc.Locale = jsonbString(nces, "locale")
145→		loc.Region = jsonbString(nces, "region_id")
146→	}
147→	if metro != nil {
148→		loc.MetroArea = jsonbString(metro, "name")
149→		loc.MetroDistance = jsonbFloat(metro, "distance")
150→	}
151→
152→	if loc.Locale == nil && loc.Region == nil && loc.MetroArea == nil && loc.MetroDistance == nil {
153→		return nil
154→	}
155→	return loc
156→}
