169→		StudentFacultyRatio:  jsonbInt(nces, "demographics_student_faculty_ratio"),
170→		FullTimeFacultyRate:  jsonbFloat(nces, "ft_faculty_rate"),
171→		Gender:               deriveGender(nces),
172→		OnlineOnly:           jsonbBool01(nces, "online_only"),
173→		CarnegieBasic:        jsonbInt(nces, "carnegie_basic"),
174→		CarnegieSizeSetting:  jsonbString(nces, "carnegie_size_setting"),
175→	}
