179→// deriveGender returns "men-only", "women-only", or "coed" based on the
180→// nces.men_only and nces.women_only JSONB values.
181→func deriveGender(nces map[string]any) *string {
182→	menOnly := jsonbBool01(nces, "men_only")
183→	womenOnly := jsonbBool01(nces, "women_only")
184→	if menOnly != nil && *menOnly {
185→		s := "men-only"
186→		return &s
187→	}
188→	if womenOnly != nil && *womenOnly {
189→		s := "women-only"
190→		return &s
191→	}
192→	// If both are present and false, or if either is missing, default to coed.
193→	if menOnly != nil || womenOnly != nil {
194→		s := "coed"
195→		return &s
196→	}
197→	return nil
198→}
